mapper.select:
SELECT m.id, m.code, m.name, c.name AS type, m.location, m.address, m.contact, m.phone, UNIX_TIMESTAMP(m.created_at) AS create_time, m.default_area_code
c.direction = 'UPSTREAM' AND m.deleted = 0 AND m.id = #{id}
AND (m.code LIKE CONCAT('%', #{blurParam}, '%') OR m.name LIKE CONCAT('%', #{blurParam}, '%'))
AND m.location = #{location}
AND EXISTS (SELECT 1 FROM biz_merchant_area ma WHERE ma.merchant_id = m.id AND ma.area_code = #{businessArea} AND ma.deleted = 0)

SELECT m.id, m.code, m.name, c.name AS type, m.location, m.address, m.bank, m.bank_card_num, m.channel, m.default_area_code, contact.name AS store_manager, UNIX_TIMESTAMP(m.created_at) AS create_time
LEFT JOIN ( SELECT s.merchant_id, s.name FROM biz_merchant_staff s JOIN biz_merchant_staff_role sr ON sr.staff_id = s.id AND sr.role_code = 'CONTACT' AND sr.deleted = 0 WHERE s.deleted = 0 ) contact ON contact.merchant_id = m.id
c.direction = 'DOWNSTREAM' AND m.deleted = 0 AND m.id = #{id}
AND (m.code LIKE CONCAT('%', #{blurParam}, '%') OR m.name LIKE CONCAT('%', #{blurParam}, '%'))
AND m.location = #{location} AND m.channel = #{channel}
AND EXISTS (SELECT 1 FROM biz_merchant_area ma WHERE ma.merchant_id = m.id AND ma.area_code = #{businessArea} AND ma.deleted = 0)
